"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[3140],{2190(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>l,frontMatter:()=>a,metadata:()=>i,toc:()=>u});const i=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-2","title":"Discourses \u2014 Book 2, Chapter 2","description":"Book 2 \u2014 Chapter 2","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-2.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-2","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-2","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"sidebar_position":3,"title":"Discourses \u2014 Book 2, Chapter 2","sidebar_label":"Book 2, Ch. 2"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 1","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-1"},"next":{"title":"Book 2, Ch. 3","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-3"}}');var s=t(4848),n=t(8453);const a={sidebar_position:3,title:"Discourses \u2014 Book 2, Chapter 2",sidebar_label:"Book 2, Ch. 2"},r="Discourses",h={},u=[{value:"Book 2 \u2014 Chapter 2",id:"book-2--chapter-2",level:2},{value:"On Peace Of Mind",id:"on-peace-of-mind",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function d(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)("div",{style:{textAlign:"center"},children:[(0,s.jsx)(o.header,{children:(0,s.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,s.jsx)(o.h2,{id:"book-2--chapter-2",children:"Book 2 \u2014 Chapter 2"}),(0,s.jsx)(o.h3,{id:"on-peace-of-mind",children:"On Peace Of Mind"})]}),"\n",(0,s.jsx)(o.p,{children:(0,s.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.p,{children:"Addressed to someone preparing for court. If your only goal is to keep your will in its natural condition \u2014 honest, trustworthy, uncompelled \u2014 you already have everything you need. No preparation is required beyond what a well-lived life has already supplied. Socrates said his whole life had been preparation for his trial; what he meant was that he had never done an unjust act."}),(0,s.jsx)(o.p,{children:"If you want to protect your body, reputation, and property as well, then prepare accordingly \u2014 clasp knees, weep, flatter. But recognize that the moment you do, you've surrendered the one thing that was actually yours. Epictetus's advice isn't to be provocative like Heraclitus; it's simply to practice until circumstances dictate themselves and you respond from principle rather than from fear. The person who hasn't trained can't be given useful specific advice \u2014 any scenario the court presents will undo them."})]}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Text"}),(0,s.jsx)(o.h2,{id:"text",children:"Text"}),(0,s.jsx)(o.p,{children:"CONSIDER, you who are going into court, what you want to maintain and where you want to end: for if you want to maintain your freedom of will in its natural condition, you have all security and facility to do so, and your trouble is over. If you wish to maintain authority over what is in your power and to keep it naturally free, and if you are content with this, what more need you attend to? For who is master of this, who can take it away from you? If you wish to be a man of honour and trust, who will forbid you? If you wish not to be hindered or compelled, what man will compel you to will to get what is against your judgement, and to will to avoid things that you do not think proper to avoid?"}),(0,s.jsx)(o.p,{children:"What can he do then? He will cause you troubles which seem to you formidable: but how can he make you will to avoid what is done to you? As long then as you retain in your control the will to get and the will to avoid, you need attend to nothing else. This is your introduction, this"}),(0,s.jsx)(o.p,{children:"your narrative, this your proof, this your victory, this your peroration, this your ground of boasting."}),(0,s.jsx)(o.p,{children:"That is why Socrates, in reply to one who reminded him to make ready for the court, said: 'Do you not think my whole life is a preparation for this?'"}),(0,s.jsx)(o.p,{children:"What kind of preparation?"}),(0,s.jsx)(o.p,{children:"'I have maintained', said he, 'what is my own.'"}),(0,s.jsx)(o.p,{children:"What do you mean?"}),(0,s.jsx)(o.p,{children:"'I never did an unjust act in my private or in my public life.' [Xenophon, Apologia Socratis, 2, 3]"}),(0,s.jsx)(o.p,{children:"But if you wish to keep what is outside you as well--your paltry body, and goods, and reputation--I advise you to begin this moment to make all possible preparation, and further to study the character of your judge and your opponent. If you must clasp his knees, clasp them; if you must weep, then weep; if you must lament, then lament. For when once you allow outward things to dominate what is your own, you had better become a slave and have done with it. Don't be drawn this way and that, wishing to be a slave one moment and free another, but be this or that simply and with all your mind, free or slave, philosopher or unenlightened, a fighting cock of spirit, or one of no spirit; either bear stroke after stroke patiently till you die, or give way at once. Let it not be your lot to suffer many blows and then give way in the end. If such conduct is shameful, get your own mind clear at once: 'Where is the nature of good and evil to be found? Where truth is. Where truth and nature are, there is caution; where truth and nature are, there is confidence.'"}),(0,s.jsx)(o.p,{children:"For what think you? If Socrates had wished to keep his outward possessions, would he have come forward and said, 'Anytus and Meletus have power to kill me, but not to harm me'? Was he so foolish as not to see that this road leads not to that end, but elsewhere? Why is it then, that he renders no account to his judges, and adds a word of provocation? Just as my friend Heraclitus, when he had an action in Rhodes concerning a plot of land and had pointed out to the judges that his arguments were just, when he came to his peroration said, 'I will not supplicate you, nor do I regard the judgement you will give; it is you who are on your trial rather than I', and so he made an end of the business. You need not speak like that, only do not supplicate. Do not add the words, 'I do not supplicate', unless, as happened to Socrates, the right time has come deliberately to provoke your judges. If, indeed, you are preparing a peroration of this sort, why do you appear in court? Why do you answer the summons? If you wish to be crucified, wait and the cross will come: but if reason requires that you should answer the summons and do your best to persuade the judge,"}),(0,s.jsx)(o.p,{children:"you must act in accordance with this, but always keeping true to yourself."}),(0,s.jsx)(o.p,{children:"On this principle it is ridiculous to say, 'Give me advice.' What advice am I to give you? Say rather, 'Enable my mind to adapt itself to the issue, whatever it may be', for the other phrase is as though a man unskilled in writing should say, 'Tell me what to write, when a name is set me to write.' For if I say 'Dion', and then yonder fellow comes forward and sets him the name not of Dion but of Theon, what is to happen? What is he to write? If you have practised writing, you can prepare yourself for anything that is dictated to you. But if you have not practised, what is the good of my making a suggestion? For if circumstances suggest something different, what will you say or what will you do? Remember then this general principle, and you will need no special suggestion. But if you fix your gaze on outward things, you must needs be tossed up and down, at the will of your master. And who is your master? He who has authority over any of those things on which you set your heart or which you will to avoid."})]})]})}function l(e={}){const{wrapper:o}={...(0,n.R)(),...e.components};return o?(0,s.jsx)(o,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8453(e,o,t){t.d(o,{R:()=>a,x:()=>r});var i=t(6540);const s={},n=i.createContext(s);function a(e){const o=i.useContext(n);return i.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),i.createElement(n.Provider,{value:o},e.children)}}}]);